  // Жезли (Вогонь) — дія, творчість, амбіції
  wands_1:  { name: { ua: "Туз Жезлів", ru: "Туз Жезлов" }, upright: { keywords: { ua: "натхнення, творча іскра, нова ініціатива, ентузіазм", ru: "вдохновение, творческая искра, новая инициатива, энтузиазм" }, general: { ua: "Сміливість знайти свій голос; час просто піти на це і реалізувати ідею.", ru: "Смелость найти свой голос; время просто решиться и реализовать идею." } }, reversed: { keywords: { ua: "затримка, відсутність пристрасті, нестача енергії, творчі блоки", ru: "задержка, отсутствие страсти, нехватка энергии, творческие блоки" }, general: { ua: "Випробування і затримки з поточними проєктами.", ru: "Испытания и задержки с текущими проектами." } } },
  wands_2:  { name: { ua: "Двійка Жезлів", ru: "Двойка Жезлов" }, upright: { keywords: { ua: "планування, перші кроки, ухвалення рішень, ризик", ru: "планирование, первые шаги, принятие решений, риск" }, general: { ua: "Усвідомлення цілей перед втіленням їх у реальність.", ru: "Осознание целей перед их воплощением в реальность." } }, reversed: { keywords: { ua: "погане планування, надмірний аналіз, бездіяльність", ru: "плохое планирование, чрезмерный анализ, бездействие" }, general: { ua: "Неналежне планування може бути причиною падіння.", ru: "Ненадлежащее планирование может быть причиной падения." } } },
  wands_3:  { name: { ua: "Трійка Жезлів", ru: "Тройка Жезлов" }, upright: { keywords: { ua: "імпульсивність, впевненість, ріст, далекоглядність", ru: "импульсивность, уверенность, рост, прозорливость" }, general: { ua: "Все навколо планів іде рівно; кроки перетворюють плани на дії.", ru: "Всё вокруг планов идёт гладко; шаги превращают планы в действия." } }, reversed: { keywords: { ua: "обмеженість, відсутність прогресу, перешкода, розчарування", ru: "ограниченность, отсутствие прогресса, препятствие, разочарование" }, general: { ua: "Не отримали досягнень, на які сподівалися; потрібен час на планування.", ru: "Не получили достижений, на которые надеялись; нужно время на планирование." } } },
  wands_4:  { name: { ua: "Четвірка Жезлів", ru: "Четвёрка Жезлов" }, upright: { keywords: { ua: "суспільство, свято, зустріч, вечірка, стабільність, приналежність", ru: "общество, праздник, встреча, вечеринка, стабильность" }, general: { ua: "Досягнення важливої віхи; возз'єднання, повернення додому.", ru: "Достижение важной вехи; объединение, возвращение домой." } }, reversed: { keywords: { ua: "відсутність підтримки, нестабільність, конфлікт удома", ru: "отсутствие поддержки, нестабильность, конфликт дома" }, general: { ua: "Досягли мети, але не відсвяткували це; невпевненість у домашній обстановці.", ru: "Достигли цели, но не отпраздновали; неуверенность в домашней обстановке." } } },
