  wands_6:  { name: { ua: "Шістка Жезлів", ru: "Шестёрка Жезлов" }, upright: { keywords: { ua: "успіх, перемога, тріумф, нагорода, визнання, гордість", ru: "успех, победа, триумф, награда, признание, гордость" }, general: { ua: "Повністю прийміть свої дари, таланти й успіхи; дозвольте світлу сяяти.", ru: "Полностью примите свои дары, таланты и успехи; позвольте свету сиять." } }, reversed: { keywords: { ua: "невдача, відсутність визнання, відсутність нагород", ru: "неудача, отсутствие признания, отсутствие наград" }, general: { ua: "Зосередьтесь на власній подорожі, не піддаючись стандартам успіху інших.", ru: "Сосредоточьтесь на своём пути, не поддаваясь чужим стандартам успеха." } } },
