  wands_8:  { name: { ua: "Вісімка Жезлів", ru: "Восьмёрка Жезлов" }, upright: { keywords: { ua: "рух, швидкість, прогрес, швидкі рішення, раптові зміни", ru: "движение, скорость, прогресс, быстрые решения, внезапные перемены" }, general: { ua: "Проєкти, що застопорилися, наберуть обертів із величезною швидкістю.", ru: "Застопорившиеся проекты наберут обороты с огромной скоростью." } }, reversed: { keywords: { ua: "очікування, повільність, хаос, затримка", ru: "ожидание, медлительность, хаос, задержка" }, general: { ua: "Робота і домашнє життя тягнуть у мільйон напрямків; зробіть крок назад.", ru: "Работа и домашняя жизнь тянут в миллион направлений; сделайте шаг назад." } } },
