  wands_10: { name: { ua: "Десятка Жезлів", ru: "Десятка Жезлов" }, upright: { keywords: { ua: "тягар, відповідальність, борг, стрес, вигорання", ru: "тяжесть, ответственность, долг, стресс, выгорание" }, general: { ua: "Вага обов'язків невдовзі стане легшою; будьте чесні щодо того, з чим можете впоратися.", ru: "Тяжесть обязанностей скоро станет легче; будьте честны насчёт того, с чем можете справиться." } }, reversed: { keywords: { ua: "невміння делегувати, крах, зрив", ru: "неумение делегировать, крах, срыв" }, general: { ua: "Варто знайти звільнення від непотрібних обов'язків і делегувати дії іншим.", ru: "Стоит найти освобождение от ненужных обязанностей и делегировать дела другим." } } },
