  wands_13: { name: { ua: "Королева Жезлів", ru: "Королева Жезлов" }, upright: { keywords: { ua: "впевненість у собі, пристрасть, рішучість, харизма, оптимізм", ru: "уверенность в себе, страсть, решительность, харизма, оптимизм" }, general: { ua: "Зростання на шляху до того, щоб стати сильною та впевненою людиною.", ru: "Рост на пути к тому, чтобы стать сильным и уверенным человеком." } }, reversed: { keywords: { ua: "вимогливість, мстивість, невпевненість, ревність, егоїзм", ru: "требовательность, мстительность, неуверенность, ревность, эгоизм" }, general: { ua: "Низька впевненість у собі; людина ховається фізично та емоційно.", ru: "Низкая уверенность в себе; человек прячется физически и эмоционально." } } },
  wands_14: { name: { ua: "Король Жезлів", ru: "Король Жезлов" }, upright: { keywords: { ua: "лідерство, бачення, загальна картина, сміливі рішення, оптимізм", ru: "лидерство, видение, общая картина, смелые решения, оптимизм" }, general: { ua: "Компетентність і здатність; ви заслужили своє місце за столом.", ru: "Компетентность и способность; вы заслужили своё место за столом." } }, reversed: { keywords: { ua: "тиранія, порочність, безсилість, слабкий лідер", ru: "тирания, порочность, бессилие, слабый лидер" }, general: { ua: "Синдром самозванця у керівній позиції; сумніви у власних здібностях.", ru: "Синдром самозванца на руководящей позиции; сомнения в собственных способностях." } } },

