// Допоміжна функція: перетворити cardId з формату застосунку (0-based для молодших арканів,
// напр. "wands_0" = Туз, "wands_13" = Король) у формат ключів цієї бази (1-based, "wands_1" = Туз).
// Старші аркани (major_0..major_21) індексуються однаково в обох місцях — без зміни.
function normalizeCardKey(cardId) {
  const parts = cardId.split('_');
  const suit = parts[0];
  const idx = parseInt(parts[1], 10);
  if (suit === 'major') return cardId;
  return `${suit}_${idx + 1}`;
}

// Допоміжна функція: побудувати компактний текстовий блок значення карти для промпта AI
function getCardMeaningText(cardId, isReversed, lang) {
  const data = TAROT_MEANINGS[normalizeCardKey(cardId)];
  if (!data) return '';
  const orientation = isReversed ? data.reversed : data.upright;
  if (!orientation) return '';
  const kw = orientation.keywords ? orientation.keywords[lang] : '';
  const gen = orientation.general ? orientation.general[lang] : '';
  const love = orientation.love ? orientation.love[lang] : '';
  const career = orientation.career ? orientation.career[lang] : '';
  const finance = orientation.finance ? orientation.finance[lang] : '';
  let parts = [];
  if (kw) parts.push(`${lang === 'ua' ? 'Ключові слова' : 'Ключевые слова'}: ${kw}`);
  if (gen) parts.push(gen);
  if (love) parts.push(`${lang === 'ua' ? 'Кохання' : 'Любовь'}: ${love}`);
  if (career) parts.push(`${lang === 'ua' ? 'Кар\'єра' : 'Карьера'}: ${career}`);
  if (finance) parts.push(`${lang === 'ua' ? 'Фінанси' : 'Финансы'}: ${finance}`);
  return parts.join(' | ');
}
